const body = $input.first().json.body || $input.first().json;
const userWish = body.message || 'Erstelle einen allgemeinen Berater';

const planPrompt = 'Du bist ein Agent-Architekt fuer das KIMANUS System. Der User beschreibt welchen Agenten er braucht. Erstelle ein JSON-Objekt mit: name (kurzer deutscher Name), role (1-2 Woerter), description (1 Satz), systemPrompt (ausfuehrlicher System-Prompt mit Persoenlichkeit und Faehigkeiten, mindestens 150 Woerter, auf Deutsch), model (deepseek/groq-llama/gemini-flash), icon (1 Emoji), category (Scouts/Guides/Berater/Business/Recht/Finanzen/Spezialisten), webhookPath (kebab-case). Antworte NUR mit validem JSON.';

const messages = [
  {role: 'system', content: planPrompt},
  {role: 'user', content: userWish}
];

return [{json: {messages, userWish}}];

const response = $input.first().json;
const content = response.choices[0].message.content;

let plan;
try {
  plan = JSON.parse(content);
} catch(e) {
  const match = content.match(/\{[\s\S]*\}/);
  if (match) plan = JSON.parse(match[0]);
  else throw new Error('Parse-Fehler: ' + content.substring(0, 300));
}

const ext = 200 + Math.floor(Math.random() * 99);
plan.phone = 'Durchwahl ' + ext;
plan.email = plan.webhookPath + '@kimanus.de';

const webhookPath = 'agent-' + plan.webhookPath;
const spJson = JSON.stringify(plan.systemPrompt);

const setupCode = 'const body=$input.first().json.body||$input.first().json;const message=body.message||\'\';const history=body.history||[];const sp=' + spJson + ';const messages=[{role:"system",content:sp},...history.slice(-20),{role:"user",content:message}];return[{json:{messages,model:"' + plan.model + '"}}];';

const extractCode = 'const r=$input.first().json;const a=r.choices&&r.choices[0]&&r.choices[0].message?r.choices[0].message.content:"Keine Antwort.";return[{json:{output:a,agent:"' + plan.name + '",model:"' + plan.model + '"}}];';

const workflowBody = {
  name: plan.name + ' - KIMANUS Agent',
  nodes: [
    {id:'wh',name:'Webhook',type:'n8n-nodes-base.webhook',typeVersion:2,position:[0,300],webhookId:webhookPath,parameters:{path:webhookPath,httpMethod:'POST',responseMode:'responseNode'}},
    {id:'setup',name:'Setup',type:'n8n-nodes-base.code',typeVersion:2,position:[250,300],parameters:{mode:'runOnceForAllItems',jsCode:setupCode}},
    {id:'llm',name:'LLM',type:'n8n-nodes-base.httpRequest',typeVersion:4.2,position:[500,300],parameters:{url:'http://litellm:4000/v1/chat/completions',method:'POST',sendHeaders:true,headerParameters:{parameters:[{name:'Authorization',value:'Bearer sk-manus-geheimschluessel-1234'},{name:'Content-Type',value:'application/json'}]},sendBody:true,specifyBody:'json',jsonBody:'={{ JSON.stringify({model:$json.model,messages:$json.messages,max_tokens:2000}) }}'}},
    {id:'extract',name:'Extract',type:'n8n-nodes-base.code',typeVersion:2,position:[750,300],parameters:{mode:'runOnceForAllItems',jsCode:extractCode}},
    {id:'respond',name:'Respond',type:'n8n-nodes-base.respondToWebhook',typeVersion:1.1,position:[1000,300],parameters:{respondWith:'json',responseBody:'={{ JSON.stringify($json) }}'}}
  ],
  connections:{
    'Webhook':{main:[[{node:'Setup',type:'main',index:0}]]},
    'Setup':{main:[[{node:'LLM',type:'main',index:0}]]},
    'LLM':{main:[[{node:'Extract',type:'main',index:0}]]},
    'Extract':{main:[[{node:'Respond',type:'main',index:0}]]}
  },
  settings:{executionOrder:'v1'}
};

return [{json: {plan, workflowBody, webhookPath}}];
